import java.nio.file.Path;
import java.util.Map;
import software.amazon.smithy.model.Model;
import software.amazon.smithy.model.shapes.SmithyIdlModelSerializer;

public final class SmithyIdRefEdgeRepro {
    public static void main(String[] args) {
        Model model = Model.assembler()
                .addUnparsedModel("test.smithy", "$version: \"2\"\n"
                        + "namespace test\n"
                        + "\n"
                        + "list IdRefs { @idRef member: String }\n"
                        + "\n"
                        + "@trait\n"
                        + "structure myTrait {\n"
                        + "    @idRef @required missing: String\n"
                        + "    @idRef @required existing: String\n"
                        + "    values: IdRefs\n"
                        + "}\n"
                        + "\n"
                        + "@myTrait(\n"
                        + "    missing: \"foo.bar#Missing\",\n"
                        + "    existing: \"foo.bar#Baz\",\n"
                        + "    values: [\"foo.bar#MissingList\", \"foo.bar#Baz\"]\n"
                        + ")\n"
                        + "string Demo\n")
                .addUnparsedModel("foo.smithy", "$version: \"2\"\n"
                        + "namespace foo.bar\n"
                        + "string Baz\n")
                .assemble()
                .unwrap();

        Map<Path, String> serialized = SmithyIdlModelSerializer.builder().build().serialize(model);
        String testOutput = serialized.get(Path.of("test.smithy"));
        if (testOutput == null) {
            throw new AssertionError("Missing serialized test namespace output: " + serialized.keySet());
        }
        System.out.println(testOutput);
        assertContains(testOutput, "missing: \"foo.bar#Missing\"");
        assertContains(testOutput, "\"foo.bar#MissingList\"");
        assertContains(testOutput, "use foo.bar#Baz");
        assertContains(testOutput, "existing: Baz");

        Model.assembler()
                .addUnparsedModel("test.smithy", testOutput)
                .addUnparsedModel("foo.bar.smithy", serialized.get(Path.of("foo.bar.smithy")))
                .assemble()
                .unwrap();
    }

    private static void assertContains(String value, String expected) {
        if (!value.contains(expected)) {
            throw new AssertionError("Expected output to contain: " + expected + "\nActual:\n" + value);
        }
    }
